class RangeModule {
public:
    RangeModule() {

    }

    void addRange(int left, int right) {
        auto it = intervals.upper_bound(left);
        if (it != intervals.begin()) {
            auto prev = std::prev(it);
            if (prev->second >= right) return;
            if (prev->second >= left) {
                left = prev->first;
                intervals.erase(prev);
            }
        }
        while (it != intervals.end() && it->first < right) {
            if (it->second >= right) break;
            right = std::max(right, it->second);
            intervals.erase(it++);
        }
        intervals.emplace_hint(it, left, right);
    }

    bool queryRange(int left, int right) {
        auto it = intervals.upper_bound(left);
        return it != intervals.begin() && std::prev(it)->second >= right;
    }

    void removeRange(int left, int right) {
        auto it = intervals.upper_bound(left);
        if (it == intervals.begin()) return;
        auto prev = std::prev(it);
        if (prev->second > right) {
            intervals.emplace_hint(it, right, prev->second);
        } else if (prev->second == right) {
            intervals.erase(prev);
        }
        if (prev != intervals.begin() && std::prev(prev)->second >= left) {
            auto pprev = std::prev(prev);
            pprev->second = std::max(pprev->second, right);
            if (pprev->second >= it->first) {
                pprev->second = std::max(pprev->second, it->second);
                intervals.erase(it);
                intervals.erase(prev);
            }
        }
    }

private:
    std::map<int, int> intervals;
};

